class Solution {
public:
    int countBinarySubstrings(string s) {
        int res = 0, prev = 0;
        for (int i = 1; i <= s.length(); i++) {
            if (s[i - 1] == s[i]) {
                prev++;
            } else {
                res += min(prev, i - 1);
                prev = 1;
            }
        }
        return res;
    }
};
```
